#include<bits/stdc++.h>
using namespace std;
int a[10001];
int w,x,y,z;
int main(){
	int n;
	cin>>n;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		if(a[i]>=0&&a[i]<=18)w++;
		if(a[i]>18&&a[i]<=35)x++;
		if(a[i]>35&&a[i]<=60)y++;
		if(a[i]>60)z++;
	}
	double ww=w,xx=x,yy=y,zz=z,nn=n;
	printf("%.2lf%\n",ww/nn*100);
	printf("%.2lf%\n",xx/nn*100);
	printf("%.2lf%\n",yy/nn*100);
	printf("%.2lf%\n",zz/nn*100);
	return 0;
}
